select ti.*
from scheduler_task_instance_his ti
left join scheduler_flow_instance_his fi on fi.id = ti.flow_instance_id



            and (fi.flow_name like concat('%', #{query.flowKeyword}, '%')
                or ti.flow_instance_id::text = #{query.flowKeyword}
                or ti.flow_id::text = #{query.flowKeyword})


            and (ti.task_name like concat('%', #{query.taskKeyword}, '%')
                or ti.id::text = #{query.taskKeyword}
                or ti.task_id::text = #{query.taskKeyword})


            and ti.status = #{query.status}


            and fi.schedule_time >= #{query.scheduleStartTime}


            and fi.schedule_time <= #{query.scheduleEndTime}


            and ti.start_time >= #{query.startTime}


            and ti.start_time <= #{query.endTime}


            and ti.end_time >= #{query.finishStartTime}


            and ti.end_time <= #{query.finishEndTime}



order by ti.start_time desc nulls last, ti.create_time desc

